  1292	    fn decodeClientKey(byte: u8) ClientKey {
  1293	        if (byte == 0) {
  1294	            return .{
  1295	                .key = ' ',
  1296	                .mods = .{ .ctrl = true },
  1297	            };
  1298	        }
  1299	        if (byte < 27) {
  1300	            return .{
  1301	                .key = @as(u21, 'a') + byte - 1,
  1302	                .mods = .{ .ctrl = true },
  1303	            };
  1304	        }
  1305	        if (byte < 32) {
  1306	            return .{
  1307	                .key = @as(u21, byte) + '@',
  1308	                .mods = .{ .ctrl = true },
  1309	            };
  1310	        }
  1311	        return .{
  1312	            .key = byte,
  1313	            .mods = .{},
  1314	        };
  1315	    }
