  1317	    fn lookupBindingCommand(self: *Server, table_name: []const u8, key: u21, mods: binding_mod.Modifiers) ?[]const u8 {
  1318	        const table = self.binding_manager.tables.get(table_name) orelse return null;
  1319	        const action = table.lookup(key, mods) orelse return null;
  1320	        return switch (action) {
  1321	            .command => |command| command,
  1322	            .none => null,
  1323	        };
  1324	    }
