  1326	    fn normalizePrefixKey(prefix_key: u21) ?u21 {
  1327	        if (prefix_key == 0) return ' ';
  1328	        if (prefix_key < 27) return @as(u21, 'a') + prefix_key - 1;
  1329	        if (prefix_key < 32) return prefix_key + '@';
  1330	        return prefix_key;
  1331	    }
