  1333	    fn matchesPrefixKey(prefix_key: u21, key: u21, mods: binding_mod.Modifiers) bool {
  1334	        const normalized = normalizePrefixKey(prefix_key) orelse return false;
  1335	        if (prefix_key < 32) {
  1336	            return mods.ctrl and !mods.meta and !mods.shift and key == normalized;
  1337	        }
  1338	        return !mods.ctrl and !mods.meta and !mods.shift and key == normalized;
  1339	    }
