  1341	    fn isSessionPrefixKey(session: *Session, key: u21, mods: binding_mod.Modifiers) bool {
  1342	        if (matchesPrefixKey(session.options.prefix_key, key, mods)) return true;
  1343	        if (session.options.prefix2_key) |prefix2_key| {
