  1349	    fn resolveClientKey(
  1350	        self: *Server,
  1351	        client: *ClientConnection,
  1352	        session: *Session,
  1353	        key: u21,
  1354	        mods: binding_mod.Modifiers,
  1355	    ) ClientKeyResolution {
  1356	        if (!client.prefix_active) {
  1357	            if (self.lookupBindingCommand("root", key, mods)) |command| {
  1358	                return .{ .command = command };
