  1573	    /// Parse an SGR mouse sequence (ESC[<btn;x;yM or ESC[<btn;x;ym),
  1574	    /// find the target pane by coordinates, adjust coordinates to pane-local,
  1575	    /// and forward the adjusted sequence to the pane's PTY.
  1576	    /// Returns true if the payload was handled as a mouse event.
  1577	    fn parseSgrMouse(
  1578	        self: *Server,
  1579	        payload: []const u8,
  1580	        window: *Window,
  1581	        default_pane: *Pane,
  1582	    ) bool {
  1583	        // SGR mouse format: ESC [ < Btn ; X ; Y [Mm]
  1584	        // Minimum length: ESC [ < 0 ; 1 ; 1 M = 10 bytes
  1585	        if (payload.len < 10) return false;
  1586	        if (payload[1] != '[' or payload[2] != '<') return false;
  1587	
  1588	        const final = payload[payload.len - 1];
  1589	        if (final != 'M' and final != 'm') return false;
  1590	
  1591	        // Parse btn;x;y from payload[3..len-1]
  1592	        const params = payload[3 .. payload.len - 1];
  1593	        var parts: [3]u32 = .{ 0, 0, 0 };
  1594	        var part_idx: usize = 0;
  1595	        for (params) |c| {
  1596	            if (c == ';') {
  1597	                part_idx += 1;
  1598	                if (part_idx >= 3) return false;
  1599	            } else if (c >= '0' and c <= '9') {
  1600	                parts[part_idx] = parts[part_idx] * 10 + (c - '0');
  1601	            } else {
  1602	                return false; // unexpected character
  1603	            }
  1604	        }
  1605	        if (part_idx != 2) return false;
  1606	
  1607	        const btn = parts[0];
  1608	        const abs_x = parts[1];
  1609	        const abs_y = parts[2];
  1610	
  1611	        // Convert from 1-based to 0-based.
  1612	        const x = if (abs_x > 0) abs_x - 1 else 0;
  1613	        const y = if (abs_y > 0) abs_y - 1 else 0;
  1614	
  1615	        // Find which pane contains these coordinates.
  1616	        var target_pane = default_pane;
  1617	        for (window.panes.items) |pane| {
  1618	            if (x >= pane.xoff and x < pane.xoff + pane.sx and
  1619	                y >= pane.yoff and y < pane.yoff + pane.sy)
  1620	            {
  1621	                target_pane = pane;
  1622	                break;
  1623	            }
  1624	        }
  1625	
  1626	        // Check if the target pane has mouse mode enabled.
  1627	        if (self.session_loop.getPane(target_pane.id)) |ps| {
  1628	            if (!ps.screen.mode.mouse_standard and !ps.screen.mode.mouse_button and
  1629	                !ps.screen.mode.mouse_any)
  1630	            {
  1631	                // Mouse not enabled on this pane — select pane on click.
  1632	                if (final == 'M' and btn == 0) {
  1633	                    window.selectPane(target_pane);
  1634	                }
  1635	                return true;
  1636	            }
  1637	        }
  1638	
  1639	        // Adjust coordinates to pane-local (1-based).
  1640	        const local_x = x - target_pane.xoff + 1;
  1641	        const local_y = y - target_pane.yoff + 1;
  1642	
  1643	        // Rebuild and forward the adjusted SGR mouse sequence.
  1644	        var buf: [32]u8 = undefined;
  1645	        const seq = std.fmt.bufPrint(&buf, "\x1b[<{d};{d};{d}{c}", .{
  1646	            btn, local_x, local_y, final,
  1647	        }) catch return false;
  1648	
  1649	        self.writePaneInput(target_pane, seq);
  1650	        return true;
  1651	    }
