   118	        if (ch == '?' or ch == ';' or (ch >= '0' and ch <= '9')) continue;
   119	        return .invalid;
   120	    }
   121	    return .need_more;
   122	}
   123	
   124	fn classifyXtVersion(bytes: []const u8) ReplyMatch {
   125	    const prefix = "\x1bP>|";
   126	    if (bytes.len == 0) return .need_more;
   127	    if (bytes.len <= prefix.len) {
   128	        if (!std.mem.eql(u8, bytes, prefix[0..bytes.len])) return .invalid;
   129	        return .need_more;
   130	    }
   131	    if (!std.mem.eql(u8, bytes[0..prefix.len], prefix)) return .invalid;
   132	    if (bytes.len >= 2 and bytes[bytes.len - 2] == 0x1b and bytes[bytes.len - 1] == '\\') return .complete;
   133	    return .need_more;
   134	}
